-- Database: microgrid_platform
-- PHP Version: 8.2.12

SET SQL_MODE='NO_AUTO_VALUE_ON_ZERO';
SET AUTOCOMMIT=0;
START TRANSACTION;


DROP TABLE IF EXISTS `alerts`;
CREATE TABLE `alerts` (
  `alert_id` bigint(20) NOT NULL AUTO_INCREMENT,
  `family_id` int(11) NOT NULL,
  `microgrid_id` int(11) DEFAULT NULL,
  `alert_type` enum('overvoltage','overcharge','battery_low','high_temperature','sensor_fault','undervoltage','system_error') NOT NULL,
  `severity` enum('info','warning','critical') DEFAULT 'warning',
  `message` varchar(500) NOT NULL,
  `status` enum('active','acknowledged','resolved') DEFAULT 'active',
  `timestamp` datetime NOT NULL DEFAULT current_timestamp(),
  `resolved_at` datetime DEFAULT NULL,
  PRIMARY KEY (`alert_id`),
  KEY `idx_family_status` (`family_id`,`status`),
  KEY `microgrid_id` (`microgrid_id`),
  CONSTRAINT `alerts_ibfk_1` FOREIGN KEY (`family_id`) REFERENCES `families` (`family_id`) ON DELETE CASCADE,
  CONSTRAINT `alerts_ibfk_2` FOREIGN KEY (`microgrid_id`) REFERENCES `microgrids` (`microgrid_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=37 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `api_keys`;
CREATE TABLE `api_keys` (
  `key_id` int(11) NOT NULL AUTO_INCREMENT,
  `family_id` int(11) NOT NULL,
  `api_key` varchar(64) NOT NULL,
  `description` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`key_id`),
  UNIQUE KEY `api_key` (`api_key`),
  KEY `family_id` (`family_id`),
  CONSTRAINT `api_keys_ibfk_1` FOREIGN KEY (`family_id`) REFERENCES `families` (`family_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `battery_status`;
CREATE TABLE `battery_status` (
  `battery_id` int(11) NOT NULL AUTO_INCREMENT,
  `family_id` int(11) NOT NULL,
  `battery_name` varchar(100) DEFAULT 'Main Battery',
  `capacity_kwh` decimal(10,2) NOT NULL DEFAULT 10.00,
  `battery_level` decimal(5,2) NOT NULL,
  `voltage` decimal(8,2) NOT NULL,
  `remaining_kwh` decimal(10,3) DEFAULT 0.000,
  `charge_status` enum('charging','discharging','idle','full') DEFAULT 'idle',
  `temperature` decimal(6,2) DEFAULT NULL,
  `timestamp` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`battery_id`),
  KEY `idx_family_time` (`family_id`,`timestamp`),
  CONSTRAINT `battery_status_ibfk_1` FOREIGN KEY (`family_id`) REFERENCES `families` (`family_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4340 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `energy_consumption`;
CREATE TABLE `energy_consumption` (
  `consumption_id` bigint(20) NOT NULL AUTO_INCREMENT,
  `family_id` int(11) NOT NULL,
  `consumed_kwh` decimal(10,3) NOT NULL,
  `timestamp` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`consumption_id`),
  KEY `idx_family_time` (`family_id`,`timestamp`),
  CONSTRAINT `energy_consumption_ibfk_1` FOREIGN KEY (`family_id`) REFERENCES `families` (`family_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2164 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `energy_readings`;
CREATE TABLE `energy_readings` (
  `reading_id` bigint(20) NOT NULL AUTO_INCREMENT,
  `microgrid_id` int(11) NOT NULL,
  `voltage` decimal(8,2) NOT NULL,
  `current_amp` decimal(8,3) NOT NULL,
  `power_kw` decimal(10,3) NOT NULL,
  `energy_kwh` decimal(10,3) DEFAULT 0.000,
  `temperature` decimal(6,2) DEFAULT NULL,
  `timestamp` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`reading_id`),
  KEY `idx_microgrid_time` (`microgrid_id`,`timestamp`),
  CONSTRAINT `energy_readings_ibfk_1` FOREIGN KEY (`microgrid_id`) REFERENCES `microgrids` (`microgrid_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17311 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `families`;
CREATE TABLE `families` (
  `family_id` int(11) NOT NULL AUTO_INCREMENT,
  `family_name` varchar(100) NOT NULL,
  `location` varchar(255) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`family_id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `microgrids`;
CREATE TABLE `microgrids` (
  `microgrid_id` int(11) NOT NULL AUTO_INCREMENT,
  `family_id` int(11) NOT NULL,
  `microgrid_name` varchar(100) NOT NULL,
  `type` enum('solar','wind') NOT NULL,
  `capacity_kw` decimal(10,2) NOT NULL,
  `location` varchar(255) DEFAULT NULL,
  `location_name` varchar(150) DEFAULT NULL,
  `latitude` decimal(10,7) DEFAULT NULL,
  `longitude` decimal(10,7) DEFAULT NULL,
  `expected_generation_kw` decimal(10,2) DEFAULT NULL,
  `installed_on` date DEFAULT NULL,
  `status` enum('active','inactive','maintenance') DEFAULT 'active',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`microgrid_id`),
  KEY `family_id` (`family_id`),
  CONSTRAINT `microgrids_ibfk_1` FOREIGN KEY (`family_id`) REFERENCES `families` (`family_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `system_logs`;
CREATE TABLE `system_logs` (
  `log_id` bigint(20) NOT NULL AUTO_INCREMENT,
  `family_id` int(11) DEFAULT NULL,
  `user_id` int(11) DEFAULT NULL,
  `microgrid_id` int(11) DEFAULT NULL,
  `event_type` varchar(60) NOT NULL,
  `severity` enum('info','warning','critical') DEFAULT 'info',
  `message` varchar(500) NOT NULL,
  `timestamp` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`log_id`),
  KEY `idx_logs_time` (`timestamp`),
  KEY `idx_logs_family` (`family_id`),
  KEY `idx_logs_event` (`event_type`)
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `tariff_settings`;
CREATE TABLE `tariff_settings` (
  `tariff_id` int(11) NOT NULL AUTO_INCREMENT,
  `tariff_name` varchar(100) NOT NULL,
  `rate_per_kwh` decimal(8,4) NOT NULL,
  `currency` varchar(10) DEFAULT 'INR',
  `effective_from` date NOT NULL,
  `effective_to` date DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  PRIMARY KEY (`tariff_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `user_id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `role` enum('admin','user') NOT NULL DEFAULT 'user',
  `family_id` int(11) DEFAULT NULL,
  `full_name` varchar(100) NOT NULL,
  `email` varchar(150) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `username` (`username`),
  KEY `family_id` (`family_id`),
  CONSTRAINT `users_ibfk_1` FOREIGN KEY (`family_id`) REFERENCES `families` (`family_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


COMMIT;
SET AUTOCOMMIT=1;
